119	// executeSegmentWithTimeout handles segment execution with timeout logic
120	func (e *Engine) executeSegmentWithTimeout(segment *config.Segment) {
121		done := make(chan bool)
122		gidChan := make(chan uint64, 1)
123	
124		go func() {
125			gidChan <- runjobs.CurrentGID()
126			segment.Execute(e.Env)
127			close(done)
128		}()
129	
130		gid := <-gidChan
131	
132		timer := time.NewTimer(time.Duration(segment.Timeout) * time.Millisecond)
133		defer timer.Stop()
134	
135		select {
136		case <-done:
137			// Completed before timeout - nothing extra to do
138		case <-timer.C:
139			log.Errorf("timeout after %dms for segment: %s", segment.Timeout, segment.Name())
140	
141			// When streaming is enabled, don't kill goroutines - let them continue executing
142			if e.Env.Flags().Streaming {
143				segment.Pending = true
144				// Note: Do NOT set segment.Enabled here - that would race with Execute()
145				// Rendering logic handles Pending state to display "..." text
146	
147				// Track this segment as pending and continue execution in background
148				e.trackPendingSegment(segment, done)
149				return
150			}
151	
152			// For non-streaming mode, kill the goroutine
153			segment.Killed = true
154			if err := runjobs.KillGoroutineChildren(gid); err != nil {
155				log.Errorf("failed to kill child processes for goroutine %d (segment: %s): %v", gid, segment.Name(), err)
156			}
157		}
158	}
